const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.client_id || !body.reason) return { json: { _empty: true, error: 'client_id and reason required' } };
const validRoles = ['client', 'advisor', 'supervisor', 'admin', 'compliance_officer'];
const role = validRoles.indexOf(body.escalated_to_role) >= 0 ? body.escalated_to_role : 'client';
return { json: {
  _authorized: true,
  lead_id: body.lead_id || null,
  client_id: body.client_id,
  conversation_id: body.conversation_id || null,
  reason: String(body.reason).slice(0, 500),
  escalated_to_role: role,
  context_summary: String(body.context_summary || '').slice(0, 4000),
  decision_id: body.decision_id || null
} };

const ctx = $('Validate').item.json;
const rows = $input.item.json;
const row = (Array.isArray(rows) ? rows[0] : rows) || {};
return { json: Object.assign({}, ctx, { escalated_to_user_id: row.id || null, recipient_email: row.email || null }) };
